"use client";

import { useEffect } from "react";
import { useLedgerStore } from "@/store/useLedgerStore";
import { Sidebar } from "@/components/Sidebar";
import { Header } from "@/components/Header";
import { StatCards } from "@/components/StatCards";
import { ChartsRow } from "@/components/ChartsRow";
import { RecentExpenses } from "@/components/RecentExpenses";
import { BillsList } from "@/components/BillsList";
import { AddEntryModal } from "@/components/AddEntryModal";

export default function Home() {
  const isHydrated = useLedgerStore((state) => state.isHydrated);
  const hydrate = useLedgerStore((state) => state.hydrate);

  useEffect(() => {
    hydrate();
  }, [hydrate]);

  if (!isHydrated) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#0E1116] text-[#8B8680] font-mono text-[13px] animate-pulse">
        Initializing terminal...
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-[#0E1116] overflow-hidden">
      {/* Sidebar Navigation */}
      <Sidebar />

      {/* Main Content Area */}
      <main className="flex-1 px-4 py-8 md:px-10 md:py-10 overflow-y-auto max-w-7xl mx-auto w-full">
        <Header />
        <StatCards />
        <ChartsRow />
        <RecentExpenses />
        <BillsList />
      </main>

      {/* Modals */}
      <AddEntryModal />
    </div>
  );
}
