"use client";

import { useLedgerStore, formatIndianCurrency } from "@/store/useLedgerStore";

export function ChartsRow() {
  const entries = useLedgerStore((state) => state.entries);

  // --- 1. Bar Chart Data (Last 6 Months) ---
  const now = new Date();
  const monthsData: { monthLabel: string; yearMonth: string; amount: number; color: string }[] = [];

  for (let i = 5; i >= 0; i--) {
    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    const yearMonth = d.toISOString().slice(0, 7);
    const monthLabel = d.toLocaleDateString("en-IN", { month: "short" });
    monthsData.push({ monthLabel, yearMonth, amount: 0, color: "#3A3E46" });
  }

  entries.forEach((entry) => {
    if (entry.type === "expense" && entry.category !== "Investment") {
      const ym = entry.date.slice(0, 7);
      const match = monthsData.find((m) => m.yearMonth === ym);
      if (match) {
        match.amount += entry.amount;
      }
    }
  });

  // Assign colors: highest in gold (#E0BD7D), second highest in sage (#6FAE98), rest neutral (#3A3E46)
  const sortedMonths = [...monthsData].sort((a, b) => b.amount - a.amount);
  if (sortedMonths.length > 0 && sortedMonths[0].amount > 0) {
    sortedMonths[0].color = "#E0BD7D"; // Gold
  }
  if (sortedMonths.length > 1 && sortedMonths[1].amount > 0) {
    sortedMonths[1].color = "#6FAE98"; // Sage Green
  }

  const maxMonthAmount = Math.max(...monthsData.map((m) => m.amount), 1000);

  // --- 2. Donut Chart Data (Current Month Categories) ---
  const currentYearMonth = now.toISOString().slice(0, 7);
  const categoryTotals: { [cat: string]: number } = {};

  entries.forEach((entry) => {
    if (entry.type === "expense" && entry.category !== "Investment" && entry.date.startsWith(currentYearMonth)) {
      categoryTotals[entry.category] = (categoryTotals[entry.category] || 0) + entry.amount;
    }
  });

  const sortedCategories = Object.entries(categoryTotals)
    .map(([category, amount]) => ({ category, amount }))
    .sort((a, b) => b.amount - a.amount);

  const topCategories = sortedCategories.slice(0, 3);
  const totalDonutAmount = topCategories.reduce((sum, c) => sum + c.amount, 0) || 1;

  const donutColors = ["#E0BD7D", "#6FAE98", "#3A3E46"];

  const radius = 40;
  const circumference = 2 * Math.PI * radius;

  // Calculate slices using reduce to maintain 100% pure immutability
  const initialReducerState: { slices: { category: string; amount: number; strokeDasharray: string; strokeDashoffset: number; color: string }[]; currentOffset: number } = {
    slices: [],
    currentOffset: 0,
  };

  const donutData = topCategories.reduce((acc, item, idx) => {
    const percentage = item.amount / totalDonutAmount;
    const dash = percentage * circumference;
    const slice = {
      ...item,
      strokeDasharray: `${dash} ${circumference}`,
      strokeDashoffset: -acc.currentOffset,
      color: donutColors[idx],
    };
    return {
      slices: [...acc.slices, slice],
      currentOffset: acc.currentOffset + dash,
    };
  }, initialReducerState);

  const donutSlices = donutData.slices;

  return (
    <section className="grid grid-cols-1 lg:grid-cols-[1.4fr_1fr] gap-4 mb-8">
      {/* Left: Monthly Expenses Bar Chart */}
      <div className="bg-[#16191F] border-hairline rounded-[10px] p-5 flex flex-col justify-between">
        <div>
          <h2 className="font-sans text-[13px] font-medium text-[#F7F5F0] mb-1">
            Monthly expenses
          </h2>
          <div className="font-mono text-[11px] text-[#8B8680] mb-6">
            Last 6 months aggregate (excl. investments)
          </div>
        </div>

        {/* SVG Bar Chart */}
        <div className="flex items-end justify-between gap-2 h-[160px] pt-4 px-2 border-b-hairline pb-2">
          {monthsData.map((item, idx) => {
            const barHeight = Math.max(8, Math.round((item.amount / maxMonthAmount) * 130));
            return (
              <div key={idx} className="flex-1 flex flex-col items-center gap-2">
                <div
                  style={{ height: `${barHeight}px`, backgroundColor: item.color }}
                  className="w-full max-w-[32px] rounded-t-[4px] transition-all duration-300 hover:brightness-110 cursor-pointer"
                  title={`${item.monthLabel}: ${formatIndianCurrency(item.amount)}`}
                />
                <span className="font-mono text-[11px] text-[#8B8680]">
                  {item.monthLabel}
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* Right: Top Category Donut Chart */}
      <div className="bg-[#16191F] border-hairline rounded-[10px] p-5 flex flex-col justify-between">
        <div>
          <h2 className="font-sans text-[13px] font-medium text-[#F7F5F0] mb-1">
            Top categories
          </h2>
          <div className="font-mono text-[11px] text-[#8B8680] mb-6">
            Current month breakdown
          </div>
        </div>

        <div className="flex items-center justify-around flex-1 gap-4">
          {/* SVG Donut */}
          <div className="relative w-[120px] h-[120px] flex items-center justify-center shrink-0">
            <svg className="w-full h-full transform -rotate-90" viewBox="0 0 100 100">
              {donutSlices.map((slice) => (
                <circle
                  key={slice.category}
                  cx="50"
                  cy="50"
                  r={radius}
                  fill="none"
                  stroke={slice.color}
                  strokeWidth="14"
                  strokeDasharray={slice.strokeDasharray}
                  strokeDashoffset={slice.strokeDashoffset}
                  className="transition-all duration-500"
                />
              ))}
            </svg>
          </div>

          {/* Legend */}
          <div className="flex flex-col gap-3 flex-1">
            {topCategories.length === 0 ? (
              <div className="font-mono text-[11px] text-[#8B8680] italic">
                No expense data this month
              </div>
            ) : (
              topCategories.map((item, idx) => (
                <div key={item.category} className="flex items-center justify-between gap-3">
                  <div className="flex items-center gap-2 truncate">
                    <div
                      className="w-2.5 h-2.5 rounded-full shrink-0"
                      style={{ backgroundColor: donutColors[idx] }}
                    />
                    <span className="font-sans text-[12px] text-[#F7F5F0] truncate">
                      {item.category}
                    </span>
                  </div>
                  <span className="font-mono text-[12px] font-bold text-[#8B8680]">
                    {formatIndianCurrency(item.amount)}
                  </span>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </section>
  );
}
