"use client";

import { useLedgerStore, formatIndianCurrency } from "@/store/useLedgerStore";

export function StatCards() {
  const entries = useLedgerStore((state) => state.entries);

  const currentYearMonth = new Date().toISOString().slice(0, 7);

  let income = 0;
  let nonInvestmentExpenses = 0;
  let investmentTotal = 0;
  let monthlySpend = 0;

  entries.forEach((entry) => {
    if (entry.type === "income") {
      income += entry.amount;
    } else {
      if (entry.category === "Investment") {
        investmentTotal += entry.amount;
      } else {
        nonInvestmentExpenses += entry.amount;
        if (entry.date.startsWith(currentYearMonth)) {
          monthlySpend += entry.amount;
        }
      }
    }
  });

  const netWorth = income - nonInvestmentExpenses;
  const goalTarget = 500000;
  const percentFunded = Math.max(0, Math.min(100, Math.round((netWorth / goalTarget) * 100)));

  return (
    <section className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
      {/* Net Worth */}
      <div className="bg-[#16191F] border-hairline rounded-[8px] p-3.5 flex flex-col justify-between">
        <div className="font-sans text-[11px] text-[#8B8680] uppercase tracking-wider mb-2">
          Net worth
        </div>
        <div className="font-mono text-[18px] sm:text-[22px] font-bold text-[#6FAE98]">
          {formatIndianCurrency(netWorth)}
        </div>
      </div>

      {/* Monthly Spend */}
      <div className="bg-[#16191F] border-hairline rounded-[8px] p-3.5 flex flex-col justify-between">
        <div className="font-sans text-[11px] text-[#8B8680] uppercase tracking-wider mb-2">
          Monthly spend
        </div>
        <div className="font-mono text-[18px] sm:text-[22px] font-bold text-[#D08077]">
          {formatIndianCurrency(monthlySpend)}
        </div>
      </div>

      {/* Investments */}
      <div className="bg-[#16191F] border-hairline rounded-[8px] p-3.5 flex flex-col justify-between">
        <div className="font-sans text-[11px] text-[#8B8680] uppercase tracking-wider mb-2">
          Investments
        </div>
        <div className="font-mono text-[18px] sm:text-[22px] font-bold text-[#F7F5F0]">
          {formatIndianCurrency(investmentTotal)}
        </div>
      </div>

      {/* Goal / Savings Progress (Special Highlight Card) */}
      <div className="bg-[#1F1A0E] border-highlight rounded-[8px] p-3.5 flex flex-col justify-between">
        <div className="font-sans text-[11px] text-[#A8895A] uppercase tracking-wider mb-2 flex justify-between items-center">
          <span>Emergency Fund</span>
          <span className="font-mono lowercase text-[10px] bg-[#E0BD7D]/10 text-[#E0BD7D] px-1.5 py-0.5 rounded">
            goal
          </span>
        </div>
        <div className="font-mono text-[18px] sm:text-[22px] font-bold text-[#E0BD7D] flex items-baseline gap-2">
          <span>{percentFunded}%</span>
          <span className="text-[11px] font-normal text-[#A8895A]">
            of {formatIndianCurrency(goalTarget)}
          </span>
        </div>
      </div>
    </section>
  );
}
