"use client";

import { useLedgerStore, formatIndianCurrency } from "@/store/useLedgerStore";

export function RecentExpenses() {
  const entries = useLedgerStore((state) => state.entries);
  const activeNav = useLedgerStore((state) => state.activeNav);
  const deleteEntry = useLedgerStore((state) => state.deleteEntry);

  // Filter entries based on activeNav
  let displayedEntries = entries;
  if (activeNav === "Expenses") {
    displayedEntries = entries.filter((e) => e.type === "expense" && e.category !== "Investment");
  } else if (activeNav === "Investments") {
    displayedEntries = entries.filter((e) => e.category === "Investment");
  } else if (activeNav === "Dashboard") {
    displayedEntries = entries.slice(0, 8); // show top 8 recent on dashboard
  }

  return (
    <div className="bg-[#16191F] border-hairline rounded-[10px] p-5 mb-8">
      <div className="flex justify-between items-center mb-6">
        <h2 className="font-sans text-[14px] font-medium text-[#F7F5F0]">
          {activeNav === "Dashboard" ? "Recent transactions" : `${activeNav} entries`}
        </h2>
        <span className="font-mono text-[11px] text-[#8B8680]">
          {displayedEntries.length} items
        </span>
      </div>

      {/* Table */}
      <div className="w-full">
        {/* Header Row — solid 1px primary-color underline (not hairline) */}
        <div className="grid grid-cols-[1.5fr_1fr_1fr_auto] sm:grid-cols-[2fr_1.5fr_1fr_1fr_auto] gap-3 pb-3 border-b border-[#F7F5F0] text-[11px] font-sans uppercase tracking-wider text-[#8B8680]">
          <div>Name</div>
          <div className="hidden sm:block">Category</div>
          <div>Date</div>
          <div className="text-right">Amount</div>
          <div className="w-6"></div>
        </div>

        {/* Rows */}
        <div className="divide-y divide-[#2A2D33]">
          {displayedEntries.length === 0 ? (
            <div className="py-10 text-center font-mono text-[12px] text-[#8B8680] italic">
              No transactions found in this view.
            </div>
          ) : (
            displayedEntries.map((entry) => {
              const isIncome = entry.type === "income";
              return (
                <div
                  key={entry.id}
                  className="grid grid-cols-[1.5fr_1fr_1fr_auto] sm:grid-cols-[2fr_1.5fr_1fr_1fr_auto] gap-3 py-3 items-center hover:bg-[#1C2027]/40 transition-colors px-1"
                >
                  <div className="font-sans font-medium text-[13px] text-[#F7F5F0] truncate">
                    {entry.name}
                  </div>
                  <div className="font-sans text-[12px] text-[#6B6E73] hidden sm:block truncate">
                    {entry.category}
                  </div>
                  <div className="font-mono text-[12px] text-[#8B8680]">
                    {entry.date}
                  </div>
                  <div
                    className={`font-mono font-bold text-[13px] text-right ${
                      isIncome ? "text-[#6FAE98]" : "text-[#D08077]"
                    }`}
                  >
                    {formatIndianCurrency(entry.amount, true, isIncome)}
                  </div>
                  <button
                    onClick={() => deleteEntry(entry.id)}
                    title="Delete transaction"
                    className="text-[#6B6E73] hover:text-[#D08077] w-6 h-6 flex items-center justify-center rounded-[5px] transition-colors text-[12px] cursor-pointer"
                  >
                    ✕
                  </button>
                </div>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
}
